/bin/bash -lc "node - <<'NODE'
function test(u,U,b){
  const flmul=(x,y)=>x*y*(1+u), flsub=(x,y)=>(x-y)*(1+u), fldiv=(x,y)=>(x/y)*(1+u);
  let x=[0,0];
  // k=1
  let s=b[1]; x[1]=fldiv(s,U[1][1]);
  // k=0
  s=flsub(b[0], flmul(U[0][1],x[1])); x[0]=fldiv(s,U[0][0]);
  const r=[U[0][0]*x[0]+U[0][1]*x[1]-b[0], U[1][1]*x[1]-b[1]];
  const lhs=Math.max(Math.abs(r[0]),Math.abs(r[1]));
  const normU=Math.max(Math.abs(U[0][0])+Math.abs(U[0][1]),Math.abs(U[1][1]));
  const normx=Math.max(Math.abs(x[0]),Math.abs(x[1]));
  const gamma=2*u/(1-2*u);
  return {lhs,rhs:gamma*normU*normx,x,r,normU,normx};
}
for (let u of [0.001,0.01,0.05,0.1,0.2,0.24]){
 let best={ratio:0};
 for(let t=0;t<200000;t++){
  const U=[[10**(Math.random()*6-3),(Math.random()*2-1)*10**(Math.random()*6-3)],[0,10**(Math.random()*6-3)]];
  const b=[(Math.random()*2-1)*10**(Math.random()*6-3),(Math.random()*2-1)*10**(Math.random()*6-3)];
  const z=test(u,U,b); const ratio=z.lhs/(z.rhs||1e-300);
  if(ratio>best.ratio) best={ratio,u,U,b,...z};
 }
 console.log('u',u,'best',best.ratio,best);
}
NODE"

