/bin/bash -lc "node - <<'NODE'
function solve(u,n,U,b){const flmul=(x,y)=>x*y*(1+u), flsub=(x,y)=>(x-y)*(1+u), fldiv=(x,y)=>(x/y)*(1+u);let x=Array(n).fill(0);for(let k=n-1;k>=0;k--){let s=b[k];for(let t=0;t<n-k-1;t++){let j=k+1+t;s=flsub(s,flmul(U[k][j],x[j]));}x[k]=fldiv(s,U[k][k]);}let r=[];for(let i=0;i<n;i++){let sum=0;for(let j=0;j<n;j++)sum+=U[i][j]*x[j];r[i]=sum-b[i];}let lhs=Math.max(...r.map(Math.abs));let normU=Math.max(...U.map(row=>row.reduce((a,v)=>a+Math.abs(v),0)));let normx=Math.max(...x.map(Math.abs));let gamma=n*u/(1-n*u);return {lhs,rhs:gamma*normU*normx,ratio:lhs/(gamma*normU*normx||1e-300),x,r,normU,normx};}
for (let n of [3,4,5]) for (let u of [0.001,0.01,0.05,0.1/(n)]){let best={ratio:0};for(let t=0;t<100000;t++){let U=Array.from({length:n},()=>Array(n).fill(0));for(let i=0;i<n;i++)for(let j=i;j<n;j++)U[i][j]=(Math.random()*2-1)*10**(Math.random()*6-3);for(let i=0;i<n;i++) if(Math.abs(U[i][i])<1e-6) U[i][i]=1;let b=Array.from({length:n},()=> (Math.random()*2-1)*10**(Math.random()*6-3));let z=solve(u,n,U,b);if(z.ratio>best.ratio) best={...z,U,b};}console.log({n,u,ratio:best.ratio,lhs:best.lhs,rhs:best.rhs});}
